if not firetouchinterest then
  getgenv().fti_orig = getgenv().fti_orig or setmetatable({}, {__mode = "k"})
  getgenv().firetouchinterest = function(part1, part2, state)
    if not (part1 and part2 and part2:FindFirstChildWhichIsA("TouchTransmitter", true)) then
        return
    end

    if state == 0 then
      getgenv().fti_orig[part2] = {
        originalCFrame = part2.CFrame,
        originalCanCollide = part2.CanCollide
      }
      part2.CanCollide = false
      part2.CFrame = part1.CFrame
    else
      local data = getgenv().fti_orig[part2]
      if data then
          part2.CFrame = data.originalCFrame
          part2.CanCollide = data.originalCanCollide
          getgenv().fti_orig[part2] = nil
      end
    end
  end
end
